package com.chaobo.scm.supplier.application.asn.event;
import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.integration.InboundEventPayloadStore;import com.chaobo.scm.supplier.application.masterdata.MasterDataEventConsumeLogPort;import com.chaobo.scm.supplier.application.shared.*;import com.chaobo.scm.supplier.domain.asn.*;import com.chaobo.scm.supplier.domain.shared.*;import com.chaobo.scm.supplier.infrastructure.persistence.asn.AsnReceiptLineMapper;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.math.BigDecimal;import java.util.*;
@Service public class WmsAsnEventConsumerApplicationService{private static final String CONSUMER="supplier-asn-wms";private final AsnRepository asns;private final MasterDataEventConsumeLogPort inbox;private final OutboxRepository outbox;private final AuditLogRepository audit;private final IdentifierGenerator ids;private final InboundEventPayloadStore payloads;private final AsnReceiptLineMapper receipts;public WmsAsnEventConsumerApplicationService(AsnRepository asns,MasterDataEventConsumeLogPort inbox,OutboxRepository outbox,AuditLogRepository audit,IdentifierGenerator ids,InboundEventPayloadStore payloads,AsnReceiptLineMapper receipts){this.asns=asns;this.inbox=inbox;this.outbox=outbox;this.audit=audit;this.ids=ids;this.payloads=payloads;this.receipts=receipts;}@Transactional public void consume(WmsAsnEvent event){var claim=inbox.claim("WMS",event.eventCode(),event.eventType(),CONSUMER,"WMS:"+event.eventCode());if(claim==MasterDataEventConsumeLogPort.ClaimResult.ALREADY_SUCCEEDED)return;if(claim==MasterDataEventConsumeLogPort.ClaimResult.IN_PROGRESS)throw new BusinessException(ErrorCode.IDEMPOTENCY_CONFLICT,"WMS ASN事件正在处理");payloads.save("WMS",event.eventCode(),CONSUMER,event);try{var asn=asns.findById(event.asnId()).orElseThrow(()->new BusinessException(ErrorCode.NOT_FOUND,"ASN不存在"));String before=snapshot(asn);switch(event.eventType()){case "WmsAppointmentConfirmed"->{if(asn.status()==AsnStatus.APPOINTED){ignored(event);return;}asn.recordAppointment(event.appointmentNo(),0,ids);}case "WmsArrivalRegistered"->{if(asn.status()==AsnStatus.ARRIVED||asn.status()==AsnStatus.RECEIVED){ignored(event);return;}asn.recordArrival(event.arrivedAt(),0,ids);}case "WmsReceiptCompleted"->{if(asn.status()==AsnStatus.RECEIVED){ignored(event);return;}validateReceipt(asn,event);asn.recordReceipt(event.receivedQuantity(),event.rejectedQuantity(),0,ids);for(var line:event.lines())receipts.insert(ids.nextId(),event.asnId(),line.asnLineId(),line.receivedQuantity(),line.rejectedQuantity(),line.qualityStatus(),line.qualityReason(),event.eventCode());}default->{ignored(event);return;}}asns.save(asn,0);var events=asn.pullEvents();outbox.saveAll(events);var context=new CommandContext(0,"WMS",0,null,"wms-"+event.eventCode(),null,"wms-"+event.eventCode(),Set.of());audit.save(context,"CONSUME_WMS_"+event.eventType(),"ASN",asn.asnId(),asn.asnNo(),before,snapshot(asn));inbox.markSucceeded("WMS",event.eventCode(),CONSUMER,false);}catch(RuntimeException exception){inbox.recordFailure("WMS",event.eventCode(),event.eventType(),CONSUMER,"WMS:"+event.eventCode(),exception.getMessage());throw exception;}}private void validateReceipt(AsnAggregate asn,WmsAsnEvent event){if(event.lines()==null||event.lines().isEmpty())throw new BusinessException(ErrorCode.VALIDATION_FAILED,"收货完成事件必须包含行级结果");var ids=asn.lines().stream().map(AsnLine::lineId).collect(java.util.stream.Collectors.toSet());if(event.lines().stream().map(WmsAsnEvent.Line::asnLineId).distinct().count()!=event.lines().size()||!event.lines().stream().allMatch(v->ids.contains(v.asnLineId())))throw new BusinessException(ErrorCode.VALIDATION_FAILED,"收货行与ASN明细不一致");BigDecimal received=event.lines().stream().map(WmsAsnEvent.Line::receivedQuantity).reduce(BigDecimal.ZERO,BigDecimal::add),rejected=event.lines().stream().map(WmsAsnEvent.Line::rejectedQuantity).reduce(BigDecimal.ZERO,BigDecimal::add);if(received.compareTo(event.receivedQuantity())!=0||rejected.compareTo(event.rejectedQuantity())!=0)throw new BusinessException(ErrorCode.VALIDATION_FAILED,"收货单头与行级数量不一致");}private void ignored(WmsAsnEvent event){inbox.markSucceeded("WMS",event.eventCode(),CONSUMER,true);}private String snapshot(AsnAggregate aggregate){return "{\"asnNo\":\"%s\",\"status\":%d,\"version\":%d}".formatted(aggregate.asnNo(),aggregate.status().code(),aggregate.version());}}
